{"id": "slQj31557EQFAMTs", "meta": {"instanceId": "82928ee63cc4a1a8a10d296c0ca2470e6c50c40295e4c3a56d6268ea258b4b94"}, "name": "Phishing Lookout and Brand Domain Monitor Workflow", "tags": [], "nodes": [{"id": "5a9b9b55-f3b5-4dad-9dd3-b08bf725f0dd", "name": "Schedule (Every Hour)", "type": "n8n-nodes-base.scheduleTrigger", "position": [592, 576], "parameters": {"rule": {"interval": [{"field": "hours"}]}}, "typeVersion": 1}, {"id": "a6fdb539-8f90-4090-9bf2-3224081ae2e6", "name": "Poll crt.sh (SSL Logs)", "type": "n8n-nodes-base.httpRequest", "notes": "Queries public SSL logs for any certificate containing 'testyourdomain.com'. CHANGE the URL query to your target brand.", "maxTries": 5, "position": [816, 576], "parameters": {"url": "=https://crt.sh/?q=%.testdomain.com&output=json", "options": {}}, "retryOnFail": true, "typeVersion": 4.1, "waitBetweenTries": 5000}, {"id": "1de5d4c1-e5f5-4cb9-b032-cd8d24df5313", "name": "Filter & Deduplicate", "type": "n8n-nodes-base.code", "position": [1264, 576], "parameters": {"jsCode": "// 1. Configuration

// Add domains to IGNORE here. You may Exclude your own domain to test how Workflow behaves but eventually add your domain below so it doesnt appear in final Alerts output 
const myDomains =["yourdomain.com","testdomain.com","google.com"]; 

// value in Hrs. reduce the hours if most recent data is needed from crt.sh
const hoursAgo = 4000;  
const cutoffDate = new Date();
cutoffDate.setHours(cutoffDate.getHours() - hoursAgo);

const alerts = [];
const seenDomains = new Set();

// 2. Processing
items.forEach(item => {
  // Use name_value from the item (Split Out creates these)
  const domain = item.json.name_value || "";

  // Use entry_timestamp if available, otherwise use current date for testing
  const rawDate = item.json.entry_timestamp || new Date().toISOString();
  const certDate = new Date(rawDate);

  // Clean wildcard prefixes (*.)
  const cleanDomain = domain.replace(/^\*\./, '');

  // LOGIC CHECKS
  const isNew = certDate > cutoffDate;
  const isSuspicious = !myDomains.includes(cleanDomain);
  const isUnique = !seenDomains.has(cleanDomain);
  const isNotEmpty = cleanDomain.length > 0;

  if (isNew && isSuspicious && isUnique && isNotEmpty) {
    seenDomains.add(cleanDomain);
    alerts.push({ json: { domain: cleanDomain, date: certDate } });
  }
});

return alerts;"}, "typeVersion": 2}, {"id": "5b663bf6-4fab-43be-9481-13b5d410f09e", "name": "Split In Batches", "type": "n8n-nodes-base.splitInBatches", "position": [1488, 576], "parameters": {"options": {}}, "typeVersion": 3}, {"id": "179f2924-4a59-4cb9-9f29-11f611c432d1", "name": "Wait for Scan", "type": "n8n-nodes-base.wait", "notes": "Wait 45s for urlscan to generate the screenshot.", "position": [1920, 512], "webhookId": "ffdc02ff-016c-43bc-90a4-a3281fe9fe37", "parameters": {"unit": "seconds", "amount": 30}, "typeVersion": 1}, {"id": "aaa47290-fbba-4a6e-8316-e550bfad4ebe", "name": "Alert Slack", "type": "n8n-nodes-base.slack", "position": [2384, 576], "webhookId": "YOUR_SLACK_WEBHOOK_HERE", "parameters": {"text": "=⚠️ *Suspicious Brand Domain Detected*

