const file = $input.first()?.json["Media"]?.[0];
const binaryData = $input.first()?.binary?.["Media"];

let mime_type = null;
let media_type = null;

if (file && binaryData) {
  mime_type = file.mimetype || "";

  if (mime_type.startsWith("image/")) {
    media_type = "IMAGE";
  } else if (mime_type.startsWith("video/")) {
    media_type = "VIDEO";
  } else if (mime_type.startsWith("audio/")) {
    media_type = "AUDIO";
  }
}

const result = {
  content: post_content,
  mime_type,
  media_type,
};

const output = {
  json: result,
};

if (binaryData) {
  // @ts-ignore
  output.binary = {
    media: binaryData,
  };
}

return [output];
