if (data.devices) {
  data.devices.forEach(device => {
    if (device.status === 'offline') {
      result.problems.push(`${device.name} is offline`);
    }
    if (device.battery && device.battery < 20) {
      result.problems.push(`${device.name} low battery: ${device.battery}%`);
    }
    if (device.temperature && device.temperature > 70) {
      result.problems.push(`${device.name} overheating: ${device.temperature}°C`);
    }
  });
}

// Generate alerts
if (result.health_score < 80) {
  result.alerts.push('System health below 80%');
}
if (result.offline_devices > 0) {
  result.alerts.push(`${result.offline_devices} devices offline`);
}

