  get_user: "Get User",
  get_many_users: "Get Many Users",
  remove_user_from_group: "Remove User from Group",
  update_user: "Update User"
};

let message = "";

if (status === "success") {
  message = `✅ ${taskMap[taskType] || "Task"} completed successfully.\n`;
  if (userName) message += `User: ${userName}\n`;
  if (groupName) message += `Group: ${groupName}\n`;
} else {
  message = `❌ ${taskMap[taskType] || "Task"} failed.\n`;
  if (userName) message += `User: ${userName}\n`;
  if (groupName) message += `Group: ${groupName}\n`;
  if (errorMsg) message += `Error: ${errorMsg}\n`;
}

