const items = $input.all();

return items.map(item => {
  const data = item.json;

  // Parse frequency (default 3 times daily)
  const timesPerDay = parseInt(data.times_per_day) || 3;
  const durationDays = parseInt(data.duration_days) || 7;

  // Standard time slots
  const timeSlots = {
    1: ['09:00'],
    2: ['09:00', '21:00'], 
    3: ['08:00', '14:00', '20:00'],
    4: ['08:00', '12:00', '16:00', '20:00']
  };

  const slots = timeSlots[timesPerDay] || timeSlots[3];
  const startDate = new Date(data.start_date || new Date());

  // Create reminders for each day and time
  const reminders = [];
  for (let day = 0; day < durationDays; day++) {
    slots.forEach(time => {
      const reminderDate = new Date(startDate);
      reminderDate.setDate(startDate.getDate() + day);
      const [hours, minutes] = time.split(':');
      reminderDate.setHours(hours, minutes, 0, 0);

      if (reminderDate > new Date()) {
        reminders.push({
          prescription_id: data.prescription_id,
          patient_name: data.patient_name,
          patient_phone: data.patient_phone,
          patient_email: data.patient_email,
          medication: data.medication,
          dosage: data.dosage,
          reminder_time: reminderDate.toISOString(),
          day_number: day + 1,
          time_slot: time,
          status: 'scheduled'
        });
      }
    });
  }

  return {
    json: {
      ...data,
      reminders: reminders,
      total_reminders: reminders.length
    }
  };
});"}, "typeVersion": 2}, {"id": "cf6ec37b-dc06-4b43-9c3d-710e0fc6559c", "name": "Save Reminders", "type": "n8n-nodes-base.googleSheets", "position": [520, 0], "parameters": {"columns": {"value": {}, "schema": [], "mappingMode": "autoMapInputData", "matchingColumns": [], "attemptToConvertTypes": false, "convertFieldsToString": false}, "options": {}, "operation": "appendOrUpdate", "sheetName": "Reminders", "documentId": {"__rl": true, "mode": "id", "value": "=0987654e3rtyhujhgfdsa"}, "authentication": "serviceAccount"}, "credentials": {"googleApi": {"id": "ScSS2KxGQULuPtdy", "name": "Google Sheets- test"}}, "typeVersion": 4}, {"id": "90bc4f7d-a268-401b-a396-a558cd1b69c9", "name": "Mark as Processed", "type": "n8n-nodes-base.googleSheets", "position": [740, 0], "parameters": {"columns": {"value": {}, "schema": [], "mappingMode": "autoMapInputData", "matchingColumns": ["prescription_id"], "attemptToConvertTypes": false, "convertFieldsToString": false}, "options": {}, "operation": "update", "sheetName": "Prescriptions", "documentId": {"__rl": true, "mode": "id", "value": "YOUR_GOOGLE_SHEET_ID"}, "authentication": "serviceAccount"}, "credentials": {"googleApi": {"id": "ScSS2KxGQULuPtdy", "name": "Google Sheets- test"}}, "typeVersion": 4}, {"id": "6c79fccb-2341-4691-883d-bb15cd535c7a", "name": "Check Every 10 Minutes", "type": "n8n-nodes-base.cron", "position": [-140, 360], "parameters": {}, "typeVersion": 1}, {"id": "5f7038d6-ee04-405a-8fe8-56ed35788e48", "name": "Get All Reminders", "type": "n8n-nodes-base.googleSheets", "position": [80, 360], "parameters": {"options": {}, "sheetName": "Reminders", "documentId": {"__rl": true, "mode": "id", "value": "=YOUR_GOOGLE_SHEET_ID"}, "authentication": "serviceAccount"}, "credentials": {"googleApi": {"id": "ScSS2KxGQULuPtdy", "name": "Google Sheets- test"}}, "typeVersion": 4}, {"id": "5f896001-4438-45f5-836d-f64f1db05ad4", "name": "Find Due Reminders", "type": "n8n-nodes-base.code", "position": [300, 360], "parameters": {"jsCode"