ersion": 2}, {"id": "392cacc9-0782-4dc9-8af6-c01f1d90fb14", "name": "✍️ Generate Personalized Message", "type": "n8n-nodes-base.code", "position": [1152, 1472], "parameters": {"jsCode": "const visitorData = $('🌐 Albacross Website Visitor').item.json;
