const hubspotData = $('📇 Create/Update HubSpot Contact').item.json;

const firstName = enrichedData.first_name || 'there';
const companyName = visitorData.company_name || 'your company';
const industry = visitorData.industry || 'your industry';
const website = visitorData.domain || '';

const personalizedMessage = `Hi ${firstName},\n\nI noticed someone from ${companyName} recently visited our website and showed interest in our solutions. As a company in the ${industry} space, I thought you might find value in how we've helped similar businesses streamline their operations and drive growth.\n\nWe've worked with several companies in your industry to:\n• Reduce operational costs by 20-30%\n• Improve efficiency through automation\n• Scale their business processes effectively\n\nI'd love to share how we could potentially help ${companyName} achieve similar results. Would you be open to a brief 15-minute call this week to discuss your current challenges and see if there's a fit?\n\nBest regards,\n[Your Name]\n[Your Title]\n[Your Company]\n[Your Phone]\n[Your Email]`;

return {
  subject: `Quick question about ${companyName}'s growth goals`,
  message: personalizedMessage,
  recipientEmail: enrichedData.email,
  recipientName: `${firstName} ${enrichedData.last_name || ''}`.trim(),
  companyName: companyName,
  hubspotContactId: hubspotData.id
};"}, "typeVersion": 2}, {"id": "031094a9-8c26-448f-bec0-377dcdc30cdb", "name": "📧 Send Personalized Email", "type": "n8n-nodes-base.gmail", "position": [1376, 1472], "webhookId": "WEBHOOK_ID", "parameters": {"sendTo": "={{ $json.recipientEmail }}", "message": "={{ $json.message }}", "options": {}, "subject": "={{ $json.subject }}"}, "credentials": {"gmailOAuth2": {"id": "GMAIL_CREDENTIALS_ID", "name": "Gmail Account"}}, "typeVersion": 2.1}, {"id": "997315ba-3d13-4a64-b00c-e5f83fae2123", "name": "📝 Log Email Activity in HubSpot", "type": "n8n-nodes-base.hubspot", "position": [1600, 1472], "parameters": {"type": "email", "metadata": {}, "resource": "engagement", "authentication": "appToken", "additionalFields": {}}, "credentials": {"hubspotAppToken": {"id": "HUBSPOT_CREDENTIALS_ID", "name": "HubSpot Account"}}, "typeVersion": 2}], "active": false, "pinData": {}, "settings": {"executionOrder": "v1"}, "versionId": "TEMPLATE_VERSION_ID", "connections": {"⏰ Schedule Trigger": {"main": [[{"node": "🌐 Albacross Website Visitor", "type": "main", "index": 0}]]}, "🔍 Enrich Lead Data": {"main": [[{"node": "📇 Create/Update HubSpot Contact", "type": "main", "index": 0}]]}, "📧 Send Personalized Email": {"main": [[{"node": "📝 Log Email Activity in HubSpot", "type": "main", "index": 0}]]}, "🌐 Albacross Website Visitor": {"main": [[{"node": "🔍 Enrich Lead Data", "type": "main", "index": 0}]]}, "📇 Create/Update HubSpot Contact": {"main": [[{"node": "✍️ Generate Personalized Message", "type": "main", "index": 0}]]}, "✍️ Generate Personalized Message": {"main": [[{"node": "📧 Send Personalized Email", "type": "main", "index": 0}]]}}}

