{"id": "xD9CDu3GF1TNqfBQ", "meta": {"instanceId": "88804d8e264d231c18413147cc92e4245b20ae7b97d774bad847556f645c8192", "templateCredsSetupCompleted": true}, "name": "Automated B2B Lead Generation from Google Maps to Google Sheets using BrowserAct", "tags": [], "nodes": [{"id": "cad3e086-dac4-4ca5-80a3-e492c6368940", "name": "When clicking ‘Execute workflow’", "type": "n8n-nodes-base.manualTrigger", "position": [-16, 208], "parameters": {}, "typeVersion": 1}, {"id": "9c04e503-f939-4c28-89bc-2cc22776cd0d", "name": "Run a workflow task", "type": "n8n-nodes-browseract-workflows.browserAct", "position": [128, 208], "parameters": {"workflowId": "56755932300135031", "inputParameters": {"parameters": [{"name": "Location", "value": "Brooklyn"}, {"name": "Bussines_Category", "value": "Baby Care "}, {"name": "Extracted_Data", "value": "15"}]}, "additionalFields": {}}, "credentials": {"browserActApi": {"id": "credential-id", "name": "browserActApi Credential"}}, "typeVersion": 1}, {"id": "2a2affd0-5b77-455e-a9e5-c08ec7d4b726", "name": "Get details of a workflow task", "type": "n8n-nodes-browseract-workflows.browserAct", "position": [288, 208], "parameters": {"taskId": "={{ $json.id }}", "operation": "getTask", "maxWaitTime": 600, "waitForFinish": true, "pollingInterval": 30}, "credentials": {"browserActApi": {"id": "credential-id", "name": "browserActApi Credential"}}, "typeVersion": 1}, {"id": "f509147d-1705-4a59-b043-0465a776fda9", "name": "Code in JavaScript", "type": "n8n-nodes-base.code", "position": [528, 208], "parameters": {"jsCode": "// Get the JSON string using the exact path provided by the user.
const jsonString = $input.first().json.output.string;

let parsedData;

// Check if the string exists before attempting to parse
if (!jsonString) {
    // Return an empty array or throw an error if no string is found
    // Throwing an error is usually better to stop the workflow if data is missing.
    throw new Error("Input string is empty or missing at the specified path: $input.first().json.output.string");
}

try {
    // 1. Parse the JSON string into a JavaScript array of objects
    parsedData = JSON.parse(jsonString);
} catch (error) {
    // Handle JSON parsing errors (e.g., if the string is malformed)
    throw new Error(`Failed to parse JSON string: ${error.message}`);
}

// 2. Ensure the parsed data is an array
if (!Array.isArray(parsedData)) {
    throw new Error('Parsed data is not an array. It cannot be split into multiple items.');
}

// 3. Map the array of objects into the n8n item format { json: object }
// Each element in this array will be treated as a new item by n8n, achieving the split.
const outputItems = parsedData.map(item => ({
    json: item,
}));

// 4. Return the new array of items
return outputItems;"}, "typeVersion": 2}, {"id": "dfed60e0-2757-4b52-9c0c-7d7e776c47d7", "name": "Append or update row in sheet", "type": "n8n-nodes-base.googleSheets", "position": [784, 208], "parameters": {"columns": {"value": {"Url": "={{ $json.Url }}", "Name": "={{ $json.Name }}", "Phone": "={{ $json.Phone }}", "Rating": "={{ $json.Rating }}", "Address": "={{ $json.Address }}", "Category": "={{ $json.Category}}", "LastSummary": "={{ $json.LastSummary }}"}, "schema": [{"id": "Name", "type": "string", "display": true, "removed": false, "required": false, "displayName": "Name", "defaultMatch": false, "canBeUsedToMatch": true}, {"id": "Phone", "type": "string", "display": true, "removed": false, "required": false, "displayName": "Phone", "defaultMatch": false, "canBeUsedToMatch": true}, {"id": "Category", "type": "string", "display": true, "removed": false, "required": false, "displayName": "Category", "defaultMatch": false, "canBeUsedToMatch": true}, {"id": "Rating", "type": "string", "display": true, "removed": false, "required": false, "displayName": "Rating", "defaultMatch": false, "canBeUsedToMatch": true}, {"id": "Address", "type": "string", "display": true, "removed": false, "required": false, "displayName": "Address", "defaultMatch": false, "canBeUsedToMatch": true}, {"id": "Url", "type": "string", "display": true, "removed": false, "required": false, "displayName": "Url", "defaultMatch": false, "canBeUsedToMatch": true}, {"id": "LastSummary", "type": "string", "display": true, "removed": false, "required": false, "displayName": "LastSummary", "defaultMatch": false, "canBeUsedToMatch": true}], "mappingMode": "defineBelow", "matchingColumns": ["Name"], "attemptToConvertTypes": false, "convertFieldsToString": false}, "options": {}, "operation": "appendOrUpdate", "sheetName": {"__rl": true, "mode": "list", "value": 1084488211, "cachedResultUrl": "https://docs.google.com/spreadsheets/d/18sw7io0yJOTDzvcknGmjBBqtK154CLk3k0FoWJZbfI0/edit#gid=1084488211", "cachedRes